        my $page = $pdf->page($page_num);

        # Extract text from each page
        my $text = $extractor->page_text($page_num);

        # Extract date
        if ($text =~ /(\d{1,2}\.\d{1,2}\.\d{2,4})/) {
            $date = $1;
        }

        # Extract author
        if ($text =~ /Author: (\w+)/i) {
            $author = $1;
        }

        # Extract tables (simplified example)
        if ($text =~ /Table\s+(\d+)/) {
            push @$tables, $1;
        }
    }

    # Return the extracted information
    return {
        date => $date,
        author => $author,
        tables => $tables,
    };
}

